insert into public.words (
  id,
  language_id,
  lemma,
  transliteration,
  pronunciation_ipa,
  part_of_speech,
  cefr_level,
  frequency_rank,
  definition,
  usage_notes
)
select
  id::uuid,
  language_id::uuid,
  lemma,
  transliteration,
  pronunciation_ipa,
  part_of_speech,
  cefr_level,
  frequency_rank,
  definition,
  usage_notes
from seeded_words
on conflict (language_id, lemma) do nothing;

with audio_languages(language_id, code, accent) as (
  values
    ('22222222-2222-2222-2222-222222222222', 'es', 'madrid'),
    ('33333333-3333-3333-3333-333333333333', 'ja', 'tokyo'),
    ('44444444-4444-4444-4444-444444444444', 'it', 'rome'),
    ('55555555-5555-5555-5555-555555555555', 'ko', 'seoul'),
    ('66666666-6666-6666-6666-666666666666', 'zh', 'beijing'),
    ('77777777-7777-7777-7777-777777777777', 'de', 'berlin')
)
insert into public.word_audio (word_id, accent, speed, audio_url, duration_ms)
select
  w.id,
  a.accent,
  s.speed,
  'https://cdn.linguadaily.app/audio/' || a.code || '/' ||
    lower(replace(replace(coalesce(nullif(w.transliteration, ''), w.lemma), ' ', '_'), '''', '')) ||
    '_' || s.speed || '.mp3',
  case when s.speed = 'native' then 1400 else 2400 end
from public.words w
join audio_languages a on a.language_id::uuid = w.language_id
cross join (values ('native'), ('slow')) as s(speed)
on conflict (word_id, accent, speed) do nothing;

